+    fn insert_rejects_zero_length_extent_without_mutating_root() {
+        let cx = test_cx();
+        let dev = MemBlockDevice::new(4096);
+        let mut root = make_root();
+        let before = root;
+        let mut alloc = SeqAllocator::new(100);
